        async function fetchDouyinInboxConversationDetail(conversationKey="",silent=false){
            const normalizedKey=normalize(conversationKey||"");
            if(!normalizedKey)return;
            if(douyinInboxConversationDetails[normalizedKey]&&Array.isArray(douyinInboxConversationDetails[normalizedKey].messages)&&douyinInboxConversationDetails[normalizedKey].messages.length)return;
            if(Number(douyinInboxDetailFailureUntil[normalizedKey]||0)>Date.now())return;
            const sourceRow=getDouyinInboxConversationRow(normalizedKey),conversation=buildDouyinInboxConversations().find(item=>normalize(item.key||"")===normalizedKey);
            if(!sourceRow||!conversation)return;
            if(normalize(douyinInboxDetailLoadingKey||"")===normalizedKey)return;
            douyinInboxDetailLoadingKey=normalizedKey;
            renderDouyinInboxWorkspace();
            try{
                const res=await fetch("/api/douyin/inbox/conversation/detail",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({account_id:Number(sourceRow.account_id||conversation.account_id||0)||0,row:sourceRow})}),data=await res.json();
                if(data.code===200&&data.detail){
                    delete douyinInboxDetailFailureUntil[normalizedKey];
                    douyinInboxConversationDetails[normalizedKey]=data.detail||{};
                    if(!silent)addLog(data.msg||`已读取 ${conversation.username||"-"} 的会话详情。`,"success");
                }else{
                    douyinInboxDetailFailureUntil[normalizedKey]=Date.now()+4000;
                    if(!silent)addLog(data.msg||data.detail||"读取会话详情失败。","error");
                }
            }catch(error){
                douyinInboxDetailFailureUntil[normalizedKey]=Date.now()+4000;
                if(!silent)addLog(`读取会话详情失败：${error.message}`,"error");
            }finally{
                if(normalize(douyinInboxDetailLoadingKey||"")===normalizedKey)douyinInboxDetailLoadingKey="";
                renderDouyinInboxWorkspace();
            }
        }
