function scheduleSearchPolling(immediate=false){if(searchPollTimer){window.clearTimeout(searchPollTimer);searchPollTimer=0}const delay=immediate?0:getSearchPollInterval();searchPollTimer=window.setTimeout(async()=>{await pollSearchPageOnce();scheduleSearchPolling(false)},delay)}
document.addEventListener('visibilitychange',()=>{scheduleSearchPolling(true)});
document.addEventListener('click',event=>{const picker=document.getElementById('search-capture-region-picker');if(!searchCaptureRegionMenuOpen||!picker)return;if(!picker.contains(event.target))closeSearchCaptureRegionMenu()});
document.addEventListener('DOMContentLoaded',async()=>{addLog('抖音搜索页面脚本已加载：page-log-20260520e。');document.getElementById('confirm-modal')?.addEventListener('click',event=>{if(event.target.id==='confirm-modal')closeConfirmModal()});document.getElementById('search-capture-modal')?.addEventListener('click',event=>{if(event.target.id==='search-capture-modal')closeSearchCaptureModal()});document.getElementById('search-task-refilter-modal')?.addEventListener('click',event=>{if(event.target.id==='search-task-refilter-modal')closeSearchTaskRefilterModal()});document.addEventListener('keydown',event=>{if(event.key!=='Escape')return;closeConfirmModal();closeSearchCaptureModal();closeSearchTaskRefilterModal();closeSearchCaptureRegionMenu()});changeDouyinCollectionMode(localStorage.getItem(douyinCollectionModeStorageKey)||"protocol",true);await loadDouyinConfig(true);await loadDouyinSearchSessions();syncCollectSessionSelection();const session=getCurrentDouyinSearchSession();if(session)applyDouyinSearchSession(session,{render:false});await updateDouyinTasks(true);renderDouyinSearchResults(douyinSearchResultData);refreshActionState();scheduleSearchPolling(false)})

loadDouyinCustomerPools = async function(options={}){if(douyinCustomerPoolsRequestInFlight&&!options.force)return douyinCustomerPoolsRequestInFlight;const request=(async()=>{try{const data=await fetchJsonWithTimeout('/api/douyin/customer-pools',5000);if(data.code!==200)throw new Error(data.msg||data.detail||'刷新客户池失败');const allRows=Array.isArray(data.all_customers)?data.all_customers:[],preciseRows=Array.isArray(data.precise_customers)?data.precise_customers:[],nextDigest=buildSearchPageDigest({all:allRows.map(row=>`${normalize(row?.user_id||row?.userId||row?.profile_url||row?.username||"")}|${normalize(row?.comment_time||row?.updated_at||"")}`),precise:preciseRows.map(row=>`${normalize(row?.user_id||row?.userId||row?.profile_url||row?.username||"")}|${normalize(row?.comment_time||row?.updated_at||"")}`)}),changed=!!options.force||nextDigest!==douyinCustomerPoolsDigest;douyinAllCustomerPool=allRows;douyinPreciseCustomerPool=preciseRows;douyinCustomerPoolsLoaded=true;douyinCustomerPoolsDirty=false;douyinCustomerPoolsDigest=nextDigest;douyinLastCustomerPoolsRefreshAt=Date.now();return changed}catch(error){if(!options.silent)addLog(`刷新客户池失败：${error.message}`,'warning');return false}})();douyinCustomerPoolsRequestInFlight=request;try{return await request}finally{if(douyinCustomerPoolsRequestInFlight===request)douyinCustomerPoolsRequestInFlight=null}};
updateDouyinTasks = async function(silent=false,options={}){try{const taskData=await fetchJsonWithTimeout('/api/douyin/tasks',5000);if(taskData.code!==200)throw new Error(taskData.msg||taskData.detail||'刷新抖音任务失败');const nextTasks=Array.isArray(taskData.tasks)?taskData.tasks:[],nextTaskDigest=buildDouyinTaskDigest(nextTasks),taskChanged=nextTaskDigest!==douyinTaskDigest,wasRunning=!!douyinIsRunning;douyinTasks=nextTasks;douyinIsRunning=!!taskData.running;if(taskChanged){douyinTaskDigest=nextTaskDigest;markDouyinCustomerPoolsStale()}let poolChanged=false;if(options.forceCustomerPools||taskChanged||!douyinCustomerPoolsLoaded||douyinCustomerPoolsDirty)poolChanged=await loadDouyinCustomerPools({silent:true,force:!!options.forceCustomerPools});const syncInterval=document.hidden?120000:(douyinIsRunning?30000:60000);let sessionsChanged=false;if(options.forceSearchSessions||taskChanged||!douyinSearchSessions.length||Date.now()-douyinLastSearchSessionSyncAt>=syncInterval){sessionsChanged=await syncDouyinSearchSessionsFromServer({silent:true,render:false,force:!!options.forceSearchSessions});douyinLastSearchSessionSyncAt=Date.now()}syncCollectSessionSelection();const captureChanged=await syncCurrentSearchCaptureState({sync:true});if(captureChanged){markDouyinCustomerPoolsStale();poolChanged=await loadDouyinCustomerPools({silent:true,force:true})||poolChanged}const shouldRender=taskChanged||poolChanged||sessionsChanged||captureChanged||wasRunning!==douyinIsRunning;if(shouldRender)renderDouyinSearchResults(douyinSearchResultData);refreshActionState();if(!silent&&shouldRender)addLog('抖音任务列表已刷新。');return shouldRender}catch(error){if(!silent)addLog(`刷新抖音任务失败：${error.message}`,'error');return false}};
getSearchPollInterval = function(){if(document.hidden)return douyinIsRunning?15000:60000;return douyinIsRunning?5000:30000};
pollSearchPageOnce = async function(){if(searchPollInFlight)return false;if(document.hidden&&!douyinIsRunning)return false;searchPollInFlight=true;try{return await updateDouyinTasks(true)}finally{searchPollInFlight=false}};
scheduleSearchPolling = function(immediate=false){if(searchPollTimer){window.clearTimeout(searchPollTimer);searchPollTimer=0}const delay=immediate&&!document.hidden?0:getSearchPollInterval();searchPollTimer=window.setTimeout(async()=>{await pollSearchPageOnce();scheduleSearchPolling(false)},delay)};
